practice_tasks.solution:
import functools

def timeout_retry(max_attempts):
  def decorator(func):
    @functools.wraps(func)
    def wrapper(*args, **kwargs):
      result = None
      for _ in range(max_attempts):
        result = func(*args, **kwargs)
      return result
    return wrapper
  return decorator

code_walkthrough.code:
def multiply_result_by(factor):
  def decorator(func):
    def wrapper(*args, **kwargs):
      return func(*args, **kwargs) * factor
    return wrapper
  return decorator

@multiply_result_by(1.2)
def get_base_price(item_id):
  return 50.0

print(get_base_price('item_42'))

