def route(path):
  print(f'Registering {path}')
  def decorator(func):
    print('Decorator attached')
    def wrapper(*args, **kwargs):
      print('Handling request')
      return func(*args, **kwargs)
    return wrapper
  return decorator

@route('/home')
def home_view():
  return 'Welcome'

print('App started')

challenge.solution:
import functools

def rate_limit(max_requests):
  def decorator(func):
    @functools.wraps(func)
    def wrapper(*args, **kwargs):
      if wrapper.calls >= max_requests:
        return 'Rate limit exceeded'
      wrapper.calls += 1
      return func(*args, **kwargs)
    wrapper.calls = 0
    return wrapper
  return decorator
